class UserMother:
    @staticmethod
    def premium_user():
        return UserFactory(role="premium", subscription_active=True)

    @staticmethod
    def banned_user():
        return UserFactory(is_banned=True, ban_reason="policy violation")


def test_premium_features_accessible(db):
    u = UserMother.premium_user()
    assert u.can_access_premium_features()

@pytest.fixture(scope="session")
def engine():
    return create_engine(TEST_DATABASE_URL)


@pytest.fixture
def db_session(engine):
    conn = engine.connect()
    tx = conn.begin()
    Session = sessionmaker(bind=conn)
    s = Session()
    yield s
    s.close()
    tx.rollback()
    conn.close()

@pytest.fixture
def setup_everything(db):
    u = User.objects.create(email=f"u{factory.Sequence}@x")  # collides under xdist
    p = Product.objects.create(...); o = Order.objects.create(user=u, product=p)
    s = Subscription.objects.create(user=u); ... # 10 more models
    return {"user": u, "product": p, "order": o, "subscription": s, ...}
